    min-width: 260px;
    background: #0a3d2e;
    display: flex;
    flex-direction: column;
    transition: width 0.3s ease, min-width 0.3s ease;
    position: relative;
    z-index: 10;
  }
  .fd-sidebar--collapsed { width: 68px; min-width: 68px; }

  .fd-sidebar__brand {
    display: flex;
